const express = require('express');
const app = express();
const PORT = 3000;

app.use(express.json());

let palaute = require('./palaute.json');

app.get('/palaute', (req, res) => {
    res.json(palaute);
});

app.get('/palaute/:id', (req, res) => {
    const id = parseInt(req.params.id);
    const item = palaute.find(p => p.id === id);

    if (item) {
        res.json(item);
    } else {
        res.status(400).json({ error: 'Ei löytynyt' });
    }
});

app.post('/palaute/uusi', (req, res) => {
    const uusi = req.body;

    if (!uusi.nimi || !uusi.viesti) {
        return res.status(400).json({ error: 'Virheellinen data' });
    }

    uusi.id = palaute.length > 0 ? palaute[palaute.length - 1].id + 1 : 1;
    palaute.push(uusi);

    res.status(200).json(uusi);
});

app.put('/palaute/:id', (req, res) => {
    const id = parseInt(req.params.id);
    const index = palaute.findIndex(p => p.id === id);

    if (index === -1) {
        return res.status(400).json({ error: 'Ei löytynyt' });
    }

    palaute[index] = {
        ...palaute[index],
        ...req.body
    };

    res.status(200).json(palaute[index]);
});

app.delete('/palaute/:id', (req, res) => {
    const id = parseInt(req.params.id);
    const index = palaute.findIndex(p => p.id === id);

    if (index === -1) {
        return res.status(400).json({ error: 'Ei löytynyt' });
    }

    const poistettu = palaute.splice(index, 1);

    res.status(200).json(poistettu[0]);
});

app.listen(PORT, () => {
    console.log(`Palvelin käynnissä portissa ${PORT}`);
});